module ring_counter_4bit(
    input clk,
    input rst,
    output [3:0] count
);

    reg [3:0] unused_shift_reg;

    always @(posedge clk) begin
        if (!rst) begin
            unused_shift_reg <= 4'b1000;
        end else begin
            unused_shift_reg <= {unused_shift_reg[2:0], unused_shift_reg[3]};
        end
    end

    assign count = unused_shift_reg;

endmodule
